/**
 * Shared proxy URL helpers for server and client. Asset keys are rewritten to
 * same-origin /api/video/... URLs. The API validates the key, generates a fresh
 * signed CDN URL, and returns a 302 redirect — the browser/Three.js fetches the
 * asset directly from Bunny. Vercel serves only the redirect, not the asset bytes.
 * Requires Bunny CDN storage zone to have CORS headers enabled (Access-Control-Allow-Origin: *).
 */ const PROXY_EXTENSIONS = [
    ".exr",
    ".hdr",
    ".glb",
    ".gltf",
    ".webm",
    ".mp4",
    ".webp",
    ".jpg",
    ".jpeg",
    ".png",
    ".avif"
];
/** Image extensions: use direct CDN URL (no proxy) so loader can append width/quality/format for Bunny. */ const IMAGE_EXTENSIONS = [
    ".webp",
    ".jpg",
    ".jpeg",
    ".png",
    ".avif"
];
function isImageRef(ref) {
    if (!ref || typeof ref !== "string") return false;
    const lower = ref.toLowerCase();
    return IMAGE_EXTENSIONS.some((ext)=>lower.endsWith(ext));
}
function needsProxyUrl(ref) {
    if (!ref || typeof ref !== "string") return false;
    const lower = ref.toLowerCase();
    return PROXY_EXTENSIONS.some((ext)=>lower.endsWith(ext));
}
function isAssetKey(value) {
    if (!value || typeof value !== "string") return false;
    if (value.startsWith("http://") || value.startsWith("https://") || value.startsWith("/api/video/") || value.startsWith("data:")) {
        return false;
    }
    return needsProxyUrl(value);
}
function buildProxyUrl(ref) {
    const path = ref.split("/").map(encodeURIComponent).join("/");
    return `/api/video/${path}`;
}
